// Pico Buzzer Melody
// Plays "Twinkle Twinkle Little Star" on a buzzer connected to GP15.

#include <Arduino.h>

const int BUZZER_PIN = 15;

// Note frequencies (Hz)
#define NOTE_C4  262
#define NOTE_D4  294
#define NOTE_E4  330
#define NOTE_F4  349
#define NOTE_G4  392
#define NOTE_A4  440
#define NOTE_B4  494
#define NOTE_C5  523
#define REST     0

// Melody: note, duration (4=quarter, 8=eighth, 2=half)
int melody[] = {
  NOTE_C4, 4,  NOTE_C4, 4,  NOTE_G4, 4,  NOTE_G4, 4,
  NOTE_A4, 4,  NOTE_A4, 4,  NOTE_G4, 2,
  NOTE_F4, 4,  NOTE_F4, 4,  NOTE_E4, 4,  NOTE_E4, 4,
  NOTE_D4, 4,  NOTE_D4, 4,  NOTE_C4, 2,
  NOTE_G4, 4,  NOTE_G4, 4,  NOTE_F4, 4,  NOTE_F4, 4,
  NOTE_E4, 4,  NOTE_E4, 4,  NOTE_D4, 2,
  NOTE_G4, 4,  NOTE_G4, 4,  NOTE_F4, 4,  NOTE_F4, 4,
  NOTE_E4, 4,  NOTE_E4, 4,  NOTE_D4, 2,
  NOTE_C4, 4,  NOTE_C4, 4,  NOTE_G4, 4,  NOTE_G4, 4,
  NOTE_A4, 4,  NOTE_A4, 4,  NOTE_G4, 2,
  NOTE_F4, 4,  NOTE_F4, 4,  NOTE_E4, 4,  NOTE_E4, 4,
  NOTE_D4, 4,  NOTE_D4, 4,  NOTE_C4, 2
};

int noteCount = sizeof(melody) / sizeof(melody[0]) / 2;

void setup() {
  pinMode(BUZZER_PIN, OUTPUT);
  Serial.begin(115200);
  delay(100);
  Serial.println("Pico Buzzer Melody - Twinkle Twinkle");
}

void loop() {
  for (int i = 0; i < noteCount; i++) {
    int note = melody[i * 2];
    int duration = 1000 / melody[i * 2 + 1];

    if (note != REST) {
      tone(BUZZER_PIN, note, duration);
      Serial.print("Note: ");
      Serial.print(note);
      Serial.println(" Hz");
    }

    delay(duration * 1.3);  // pause between notes
    noTone(BUZZER_PIN);
  }

  Serial.println("--- Melody complete, restarting ---");
  delay(2000);
}
